@contextlib.contextmanager
def module_argv(module_name: str, argv: Sequence[object]):
    old_argv = sys.argv[:]
    sys.argv = [module_name] + [str(item) for item in argv]
    try:
        yield
    finally:
        sys.argv = old_argv


def run_module_main(module: types.ModuleType, argv: Sequence[object]) -> None:
    print("running embedded module:", module.__name__, " ".join(str(item) for item in argv), flush=True)
    with module_argv(module.__name__, argv):
        rc = module.main()
    if rc not in (None, 0):
        raise SystemExit(rc)


